// Fused RoPE cos/sin embedding generation (SOL-ExecBench problem 012).
//
// reference: emb = cat(freqs, freqs); cos = emb.cos()*scale -> bf16;
//            sin = emb.sin()*scale -> bf16.  Since cos/sin are elementwise and
//            the second half of `emb` duplicates the first, each unique freq
//            produces one (cos,sin) pair written to BOTH halves of the row.
//
// This kernel loads each fp32 freq exactly once (256-bit vectorized loads),
// computes cos+sin with a single accurate `sincosf`, scales, casts to bf16, and
// writes packed 128-bit (uint4 = 8 bf16) stores to both output halves — no
// `cat` intermediate, one kernel launch, one HBM read + two HBM writes.
//
// Why C++/CUDA over the Triton parent: every scored workload is tiny
// (SOL 0.5–3.9us, all data <=27MB) => latency/overhead-bound, not
// bandwidth-bound.  CUPTI times pure on-GPU kernel span, so the lever is a lean
// single-wave kernel body + spreading the work across as many SMs as the shape
// allows.  Grid/block are sized so grid >= ~148 blocks whenever the shape has
// enough work, engaging all memory partitions in one wave.
//
// Numerics: the harness compiles with empty cuda_cflags (NO --use_fast_math),
// so `sincosf` is the accurate device routine — it matches torch.cos/sin to well
// within the bf16 cast and the loose 5% rtol / 0.99 matched-ratio gate.

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <tuple>

#define VEC 8  // freqs processed per thread (half_dim=64 => 8 chunks/row)

__device__ __forceinline__ unsigned pack2(float a, float b) {
    // {a -> low bf16, b -> high bf16} packed into one 32-bit word.
    __nv_bfloat162 p = __floats2bfloat162_rn(a, b);
    return *reinterpret_cast<unsigned*>(&p);
}

// Vectorized path: half_dim is a multiple of VEC (always 64 here).
__global__ void fused_rope_vec_kernel(
        const float* __restrict__ freqs,
        __nv_bfloat16* __restrict__ cos_out,
        __nv_bfloat16* __restrict__ sin_out,
        long n_rows,
        int half_dim,
        int full_dim,
        int chunks_per_row,
        float scale) {
    const long total_chunks = n_rows * (long)chunks_per_row;
    const long stride = (long)gridDim.x * blockDim.x;
    for (long c = (long)blockIdx.x * blockDim.x + threadIdx.x;
         c < total_chunks; c += stride) {
        const long row  = c / chunks_per_row;
        const int  col0 = (int)(c - row * chunks_per_row) * VEC;

        // One 256-bit load (two aligned float4) => 8 fp32 freqs.
        const float4* fp = reinterpret_cast<const float4*>(freqs + row * half_dim + col0);
        float4 a = fp[0];
        float4 b = fp[1];

        float s0, s1, s2, s3, s4, s5, s6, s7;
        float c0, c1, c2, c3, c4, c5, c6, c7;
        sincosf(a.x, &s0, &c0); sincosf(a.y, &s1, &c1);
        sincosf(a.z, &s2, &c2); sincosf(a.w, &s3, &c3);
        sincosf(b.x, &s4, &c4); sincosf(b.y, &s5, &c5);
        sincosf(b.z, &s6, &c6); sincosf(b.w, &s7, &c7);

        uint4 cvec = make_uint4(
            pack2(c0 * scale, c1 * scale), pack2(c2 * scale, c3 * scale),
            pack2(c4 * scale, c5 * scale), pack2(c6 * scale, c7 * scale));
        uint4 svec = make_uint4(
            pack2(s0 * scale, s1 * scale), pack2(s2 * scale, s3 * scale),
            pack2(s4 * scale, s5 * scale), pack2(s6 * scale, s7 * scale));

        __nv_bfloat16* c_lo = cos_out + row * full_dim + col0;
        __nv_bfloat16* s_lo = sin_out + row * full_dim + col0;
        // Replicate cat(freqs,freqs): same value to [col0..] and [col0+half..].
        *reinterpret_cast<uint4*>(c_lo)            = cvec;
        *reinterpret_cast<uint4*>(c_lo + half_dim) = cvec;
        *reinterpret_cast<uint4*>(s_lo)            = svec;
        *reinterpret_cast<uint4*>(s_lo + half_dim) = svec;
    }
}

// Scalar fallback (half_dim not a multiple of VEC — never hit for head_dim=128,
// kept only so an unexpected shape yields a correct result instead of OOB).
__global__ void fused_rope_scalar_kernel(
        const float* __restrict__ freqs,
        __nv_bfloat16* __restrict__ cos_out,
        __nv_bfloat16* __restrict__ sin_out,
        long n_rows, int half_dim, int full_dim, float scale) {
    const long total = n_rows * (long)half_dim;
    const long stride = (long)gridDim.x * blockDim.x;
    for (long i = (long)blockIdx.x * blockDim.x + threadIdx.x; i < total; i += stride) {
        const long row = i / half_dim;
        const int  col = (int)(i - row * half_dim);
        float s, c; sincosf(freqs[i], &s, &c);
        __nv_bfloat16 cb = __float2bfloat16(c * scale);
        __nv_bfloat16 sb = __float2bfloat16(s * scale);
        cos_out[row * full_dim + col]            = cb;
        cos_out[row * full_dim + col + half_dim] = cb;
        sin_out[row * full_dim + col]            = sb;
        sin_out[row * full_dim + col + half_dim] = sb;
    }
}

std::tuple<torch::Tensor, torch::Tensor> run(torch::Tensor freqs, double attention_scaling) {
    freqs = freqs.contiguous();
    TORCH_CHECK(freqs.scalar_type() == torch::kFloat32, "freqs must be float32");
    TORCH_CHECK(freqs.is_cuda(), "freqs must be a CUDA tensor");
    TORCH_CHECK(freqs.dim() >= 1, "freqs must have >=1 dim");

    const int64_t half_dim = freqs.size(-1);
    const int64_t full_dim = half_dim * 2;
    const int64_t n_rows   = (half_dim > 0) ? (freqs.numel() / half_dim) : 0;

    auto out_shape = freqs.sizes().vec();
    out_shape.back() = full_dim;
    auto opts = freqs.options().dtype(torch::kBFloat16);
    torch::Tensor cos = torch::empty(out_shape, opts);
    torch::Tensor sin = torch::empty(out_shape, opts);

    if (n_rows == 0 || half_dim == 0) return std::make_tuple(cos, sin);

    const float scale = static_cast<float>(attention_scaling);
    auto* fptr = freqs.data_ptr<float>();
    auto* cptr = reinterpret_cast<__nv_bfloat16*>(cos.data_ptr());
    auto* sptr = reinterpret_cast<__nv_bfloat16*>(sin.data_ptr());
    cudaStream_t stream = at::cuda::getCurrentCUDAStream().stream();

    const long GRID_CAP = 148L * 64;  // grid-stride handles anything larger

    if (half_dim % VEC == 0) {
        const int  chunks_per_row = (int)(half_dim / VEC);
        const long tc = n_rows * (long)chunks_per_row;
        // Shrink block until grid >= ~148 (spread tiny shapes across all SMs).
        int  block = 256;
        long grid  = (tc + block - 1) / block;
        if (grid < 148) { block = 128; grid = (tc + block - 1) / block; }
        if (grid < 148) { block = 64;  grid = (tc + block - 1) / block; }
        if (grid < 148) { block = 32;  grid = (tc + block - 1) / block; }
        if (grid < 1) grid = 1;
        if (grid > GRID_CAP) grid = GRID_CAP;
        fused_rope_vec_kernel<<<(unsigned)grid, block, 0, stream>>>(
            fptr, cptr, sptr, n_rows, (int)half_dim, (int)full_dim, chunks_per_row, scale);
    } else {
        const long total = n_rows * half_dim;
        int  block = 256;
        long grid  = (total + block - 1) / block;
        if (grid < 148) { block = 64; grid = (total + block - 1) / block; }
        if (grid < 1) grid = 1;
        if (grid > GRID_CAP) grid = GRID_CAP;
        fused_rope_scalar_kernel<<<(unsigned)grid, block, 0, stream>>>(
            fptr, cptr, sptr, n_rows, (int)half_dim, (int)full_dim, scale);
    }
    return std::make_tuple(cos, sin);
}

// Robust scalar marshaling: harness passes attention_scaling as a Python float
// (ScalarInput.value); the Tensor overload is insurance for a 0-d tensor.
std::tuple<torch::Tensor, torch::Tensor> run_tensor_scale(torch::Tensor freqs,
                                                          torch::Tensor scaling) {
    return run(freqs, scaling.item<double>());
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "Fused RoPE cos/sin embedding generation (scalar scale)");
    m.def("run", &run_tensor_scale, "Fused RoPE cos/sin embedding generation (tensor scale)");
}

// Fused RoPE cos/sin embedding generation for SOL-ExecBench problem 012.
//
// reference: emb = cat(freqs, freqs, dim=-1)        # [B,S,64] -> [B,S,128]
//            cos = (emb.cos() * scale).to(bf16)
//            sin = (emb.sin() * scale).to(bf16)
//
// This CUDA kernel loads each fp32 frequency exactly once via 128-bit float4
// loads, computes both sin and cos with a single __sincosf SFU instruction,
// scales in fp32, rounds to bf16 with __floats2bfloat162_rn, and writes packed
// 128-bit (uint4 = 8 bf16) stores to BOTH halves of cos and sin -- replicating
// the cat without materialising any intermediate fp32 tensor.
//
// Numerics: __sincosf is the fast SFU intrinsic. The scored RoPE frequencies
// are bounded by ~1e3 rad here, well inside the range where its absolute error
// (~1e-4) is dwarfed by the bf16 cast and the 0.99-matched / 5% rtol tolerance.
//
// Launch policy: every scored workload is tiny (largest ~27 MB / SOL ~4 us,
// most <= ~1 MB / SOL ~0.5 us), so the regime is kernel launch/scheduling
// overhead-bound rather than raw HBM-bandwidth-bound.  We therefore use a
// *natural* grid (grid = ceil(total_chunks / block)) with a per-size block
// heuristic: very large blocks for the smallest tensors (minimal scheduling
// overhead), stepping down only for the one genuinely large shape
// (B=64, S=541, ~277 k chunks) so that enough blocks stay in flight.

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <tuple>

#define VEC 8  // fp32 freqs processed per thread; must divide half_dim=64

// Pack two fp32 values into a 32-bit word holding two bf16 values
// (round-to-nearest-even matches PyTorch's .to(torch.bfloat16)).
__device__ __forceinline__ unsigned pack2(float a, float b) {
    __nv_bfloat162 p = __floats2bfloat162_rn(a, b);
    return *reinterpret_cast<unsigned*>(&p);
}

// Vectorised path: half_dim is a multiple of VEC (guaranteed for head_dim=128).
__global__ void fused_rope_vec_kernel(
        const float* __restrict__ freqs,
        __nv_bfloat16* __restrict__ cos_out,
        __nv_bfloat16* __restrict__ sin_out,
        long n_rows,
        int half_dim,
        int full_dim,
        int chunks_per_row,
        float scale) {
    const long total_chunks = n_rows * (long)chunks_per_row;
    const long stride = (long)gridDim.x * blockDim.x;

    for (long c = (long)blockIdx.x * blockDim.x + threadIdx.x;
         c < total_chunks; c += stride) {
        const long row  = c / chunks_per_row;
        const int  col0 = (int)(c - row * chunks_per_row) * VEC;

        // 8 consecutive fp32 freqs == two aligned float4 loads.
        const float4 a0 = reinterpret_cast<const float4*>(
                              freqs + row * half_dim + col0)[0];
        const float4 a1 = reinterpret_cast<const float4*>(
                              freqs + row * half_dim + col0 + 4)[0];

        float s0, s1, s2, s3, s4, s5, s6, s7;
        float c0, c1, c2, c3, c4, c5, c6, c7;
        __sincosf(a0.x, &s0, &c0); __sincosf(a0.y, &s1, &c1);
        __sincosf(a0.z, &s2, &c2); __sincosf(a0.w, &s3, &c3);
        __sincosf(a1.x, &s4, &c4); __sincosf(a1.y, &s5, &c5);
        __sincosf(a1.z, &s6, &c6); __sincosf(a1.w, &s7, &c7);

        uint4 cvec = make_uint4(
            pack2(c0 * scale, c1 * scale), pack2(c2 * scale, c3 * scale),
            pack2(c4 * scale, c5 * scale), pack2(c6 * scale, c7 * scale));
        uint4 svec = make_uint4(
            pack2(s0 * scale, s1 * scale), pack2(s2 * scale, s3 * scale),
            pack2(s4 * scale, s5 * scale), pack2(s6 * scale, s7 * scale));

        __nv_bfloat16* c_lo = cos_out + row * full_dim + col0;
        __nv_bfloat16* s_lo = sin_out + row * full_dim + col0;

        // Replicate cat(freqs, freqs): same value to column col0 and col0+64.
        *reinterpret_cast<uint4*>(c_lo)                = cvec;
        *reinterpret_cast<uint4*>(c_lo + half_dim)     = cvec;
        *reinterpret_cast<uint4*>(s_lo)                = svec;
        *reinterpret_cast<uint4*>(s_lo + half_dim)     = svec;
    }
}

// Scalar fallback for arbitrary half_dim (not used by the scored shapes, kept
// for correctness if an unexpected shape is supplied).
__global__ void fused_rope_scalar_kernel(
        const float* __restrict__ freqs,
        __nv_bfloat16* __restrict__ cos_out,
        __nv_bfloat16* __restrict__ sin_out,
        long n_rows,
        int half_dim,
        int full_dim,
        float scale) {
    const long total = n_rows * (long)half_dim;
    const long stride = (long)gridDim.x * blockDim.x;

    for (long i = (long)blockIdx.x * blockDim.x + threadIdx.x;
         i < total; i += stride) {
        const long row = i / half_dim;
        const int  col = (int)(i - row * half_dim);

        float s, c;
        __sincosf(freqs[i], &s, &c);

        __nv_bfloat16 cb = __float2bfloat16_rn(c * scale);
        __nv_bfloat16 sb = __float2bfloat16_rn(s * scale);

        cos_out[row * full_dim + col]            = cb;
        cos_out[row * full_dim + col + half_dim] = cb;
        sin_out[row * full_dim + col]            = sb;
        sin_out[row * full_dim + col + half_dim] = sb;
    }
}

std::tuple<torch::Tensor, torch::Tensor> run(torch::Tensor freqs,
                                             double attention_scaling) {
    freqs = freqs.contiguous();

    TORCH_CHECK(freqs.is_cuda(), "freqs must be a CUDA tensor");
    TORCH_CHECK(freqs.scalar_type() == torch::kFloat32,
                "freqs must be float32");
    TORCH_CHECK(freqs.dim() >= 1, "freqs must have at least one dimension");

    const int64_t half_dim = freqs.size(-1);
    const int64_t full_dim = half_dim * 2;
    const int64_t n_rows = (half_dim > 0) ? (freqs.numel() / half_dim) : 0;

    auto out_shape = freqs.sizes().vec();
    out_shape.back() = full_dim;
    auto opts = freqs.options().dtype(torch::kBFloat16);

    torch::Tensor cos = torch::empty(out_shape, opts);
    torch::Tensor sin = torch::empty(out_shape, opts);

    if (n_rows == 0 || half_dim == 0) {
        return std::make_tuple(cos, sin);
    }

    const float scale = static_cast<float>(attention_scaling);
    const float* fptr = freqs.data_ptr<float>();
    __nv_bfloat16* cptr = reinterpret_cast<__nv_bfloat16*>(cos.data_ptr());
    __nv_bfloat16* sptr = reinterpret_cast<__nv_bfloat16*>(sin.data_ptr());
    cudaStream_t stream = at::cuda::getCurrentCUDAStream().stream();

    if (half_dim % VEC == 0) {
        const int chunks_per_row = static_cast<int>(half_dim / VEC);
        const long total_chunks = n_rows * static_cast<long>(chunks_per_row);

        // Per-shape block heuristic tuned for the 16 scored workloads.
        // Larger blocks -> fewer blocks and less scheduling overhead on tiny
        // shapes; smaller blocks -> more parallelism on the one large shape.
        int block = 256;
        if (total_chunks <= 8192) {
            block = 1024;          // very small: grid 4-8
        } else if (total_chunks <= 32768) {
            block = 512;           // small: grid 32-64
        } else if (total_chunks <= 131072) {
            block = 256;           // medium: grid 128-512
        } else {
            block = 128;           // large (B=64, S=541): grid ~2164
        }

        long grid = (total_chunks + block - 1) / block;
        if (grid < 1) grid = 1;

        fused_rope_vec_kernel<<<(unsigned)grid, block, 0, stream>>>(
            fptr, cptr, sptr,
            n_rows,
            static_cast<int>(half_dim),
            static_cast<int>(full_dim),
            chunks_per_row,
            scale);
        C10_CUDA_KERNEL_LAUNCH_CHECK();
    } else {
        const long total = n_rows * half_dim;

        int block = 256;
        long grid = (total + block - 1) / block;
        if (grid < 1) grid = 1;

        fused_rope_scalar_kernel<<<(unsigned)grid, block, 0, stream>>>(
            fptr, cptr, sptr,
            n_rows,
            static_cast<int>(half_dim),
            static_cast<int>(full_dim),
            scale);
        C10_CUDA_KERNEL_LAUNCH_CHECK();
    }

    return std::make_tuple(cos, sin);
}

// Insurance overload for when the harness passes the scalar as a 0-d tensor.
std::tuple<torch::Tensor, torch::Tensor> run_tensor_scale(torch::Tensor freqs,
                                                          torch::Tensor scaling) {
    return run(freqs, scaling.item<double>());
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run,
          "Fused RoPE cos/sin embedding generation (scalar scale)");
    m.def("run", &run_tensor_scale,
          "Fused RoPE cos/sin embedding generation (tensor scale)");
}

// Problem 012 — Fused cos/sin embedding generation (RoPE), CUDA.
//
// Reference: emb = cat(freqs, freqs); cos = emb.cos()*scale -> bf16;
//            sin = emb.sin()*scale -> bf16.  freqs is [B,S,64] fp32, outputs
//            are [B,S,128] bf16.  head_dim=128 (const) so half=64.
//
// Design (why this can edge past the Triton flat frontier):
//   * Each unique frequency's (cos,sin) is written to TWO output columns
//     (col and col+64) — we compute the SFU work ONCE and duplicate the store,
//     halving transcendental work vs the reference (which cos/sin's the cat'd
//     128-wide tensor).
//   * 2 frequencies per thread: one 8-byte float2 load, and PACKED 32-bit
//     __nv_bfloat162 stores (two adjacent bf16 at once) to each half — wider
//     memory transactions and better ILP than Triton's scalar bf16 stores.
//     2 adjacent freqs are always in the same 64-wide row (64 is even), and
//     both low- and high-half targets are 4-byte aligned (even element index),
//     so the packed stores are always legal.
//   * NATURAL grid = cdiv(n_pairs, 256) — does NOT over-spread onto tiny
//     32-thread blocks (the mistake that sank the prior CUDA attempt); these
//     L2/launch-floor-bound shapes want few large blocks.
//   * Robust trig under the harness's default --use_fast_math: double-precision
//     range reduction to [-pi,pi] first, THEN __sincosf on the reduced value
//     (accurate to ~2^-21 there, far below the bf16 rounding step of 2^-8), so
//     the result matches the reference's accurate cosf/sinf for ANY freq
//     magnitude — well inside the 1e-5 atol / 0.05 rtol / 99%-match gate.

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_bf16.h>
#include <tuple>

#define HALF 64
#define FULL 128

__global__ void fused_rope_kernel(const float* __restrict__ freqs,
                                  __nv_bfloat16* __restrict__ cos_out,
                                  __nv_bfloat16* __restrict__ sin_out,
                                  long n_pairs, float scale) {
    long t = (long)blockIdx.x * blockDim.x + threadIdx.x;
    if (t >= n_pairs) return;

    // One 8-byte load pulls two consecutive frequencies (same row).
    const float2 f = reinterpret_cast<const float2*>(freqs)[t];

    // Accurate range reduction in double, robust to large arguments and to
    // --use_fast_math turning __sincosf into the hardware MUFU path.
    const double TWO_PI = 6.283185307179586476925286766559;
    double x0 = (double)f.x;
    double x1 = (double)f.y;
    float r0 = (float)(x0 - TWO_PI * rint(x0 / TWO_PI));
    float r1 = (float)(x1 - TWO_PI * rint(x1 / TWO_PI));

    float s0, c0, s1, c1;
    __sincosf(r0, &s0, &c0);
    __sincosf(r1, &s1, &c1);

    // fp32 scale, then round-to-nearest-even into bf16 (matches torch .to(bf16)).
    __nv_bfloat162 cpair = __floats2bfloat162_rn(c0 * scale, c1 * scale);
    __nv_bfloat162 spair = __floats2bfloat162_rn(s0 * scale, s1 * scale);

    // Map the pair back to output positions.  two_t is the low-half element
    // index; the high half is +64.  Both are even -> 4-byte aligned bf162.
    long two_t = t << 1;
    long row   = two_t >> 6;          // / 64
    long col   = two_t & (HALF - 1);  // % 64
    long lo    = (row << 7) + col;    // row*128 + col
    long hi    = lo + HALF;

    __nv_bfloat162* cptr = reinterpret_cast<__nv_bfloat162*>(cos_out);
    __nv_bfloat162* sptr = reinterpret_cast<__nv_bfloat162*>(sin_out);
    cptr[lo >> 1] = cpair;   // cos[..., col : col+2]
    cptr[hi >> 1] = cpair;   // cos[..., col+64 : col+66]  (duplicate)
    sptr[lo >> 1] = spair;
    sptr[hi >> 1] = spair;
}

std::tuple<torch::Tensor, torch::Tensor> run(torch::Tensor freqs,
                                             double attention_scaling) {
    freqs = freqs.contiguous();
    const int64_t B    = freqs.size(0);
    const int64_t S    = freqs.size(1);
    const int64_t half = freqs.size(2);   // 64
    const int64_t full = half * 2;        // 128
    const int64_t n_freqs = B * S * half;
    const int64_t n_pairs = n_freqs / 2;  // n_freqs is a multiple of 64 -> even

    auto opts = torch::TensorOptions().dtype(torch::kBFloat16).device(freqs.device());
    auto cos_out = torch::empty({B, S, full}, opts);
    auto sin_out = torch::empty({B, S, full}, opts);

    if (n_pairs > 0) {
        const int block = 256;
        const int grid = (int)((n_pairs + block - 1) / block);
        cudaStream_t stream = at::cuda::getCurrentCUDAStream().stream();
        fused_rope_kernel<<<grid, block, 0, stream>>>(
            freqs.data_ptr<float>(),
            reinterpret_cast<__nv_bfloat16*>(cos_out.data_ptr<at::BFloat16>()),
            reinterpret_cast<__nv_bfloat16*>(sin_out.data_ptr<at::BFloat16>()),
            n_pairs, (float)attention_scaling);
    }
    return std::make_tuple(cos_out, sin_out);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "fused cos/sin RoPE embedding generation (CUDA)");
}

// Problem 012 — Fused cos/sin embedding generation (RoPE), CUDA.
//
// Reference: emb = cat(freqs, freqs); cos = emb.cos()*scale -> bf16;
//            sin = emb.sin()*scale -> bf16.  freqs is [B,S,64] fp32, outputs
//            are [B,S,128] bf16.  head_dim=128 (const) so half=64.
//
// Design (why this can edge past the Triton flat frontier):
//   * Each unique frequency's (cos,sin) is written to TWO output columns
//     (col and col+64) — we compute the SFU work ONCE and duplicate the store,
//     halving transcendental work vs the reference (which cos/sin's the cat'd
//     128-wide tensor).
//   * 2 frequencies per thread: one 8-byte float2 load, and PACKED 32-bit
//     __nv_bfloat162 stores (two adjacent bf16 at once) to each half — wider
//     memory transactions and better ILP than Triton's scalar bf16 stores.
//     2 adjacent freqs are always in the same 64-wide row (64 is even), and
//     both low- and high-half targets are 4-byte aligned (even element index),
//     so the packed stores are always legal.
//   * NATURAL grid = cdiv(n_pairs, 256) — does NOT over-spread onto tiny
//     32-thread blocks (the mistake that sank the prior CUDA attempt); these
//     L2/launch-floor-bound shapes want few large blocks.
//   * Robust trig under the harness's default --use_fast_math: double-precision
//     range reduction to [-pi,pi] first, THEN __sincosf on the reduced value
//     (accurate to ~2^-21 there, far below the bf16 rounding step of 2^-8), so
//     the result matches the reference's accurate cosf/sinf for ANY freq
//     magnitude — well inside the 1e-5 atol / 0.05 rtol / 99%-match gate.

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_bf16.h>
#include <tuple>

#define HALF 64
#define FULL 128

__global__ void fused_rope_kernel(const float* __restrict__ freqs,
                                  __nv_bfloat16* __restrict__ cos_out,
                                  __nv_bfloat16* __restrict__ sin_out,
                                  long n_pairs, float scale) {
    long t = (long)blockIdx.x * blockDim.x + threadIdx.x;
    if (t >= n_pairs) return;

    // One 8-byte load pulls two consecutive frequencies (same row).
    const float2 f = reinterpret_cast<const float2*>(freqs)[t];

    // Accurate range reduction in double, robust to large arguments and to
    // --use_fast_math turning __sincosf into the hardware MUFU path.
    const double TWO_PI = 6.283185307179586476925286766559;
    double x0 = (double)f.x;
    double x1 = (double)f.y;
    float r0 = (float)(x0 - TWO_PI * rint(x0 / TWO_PI));
    float r1 = (float)(x1 - TWO_PI * rint(x1 / TWO_PI));

    float s0, c0, s1, c1;
    __sincosf(r0, &s0, &c0);
    __sincosf(r1, &s1, &c1);

    // fp32 scale, then round-to-nearest-even into bf16 (matches torch .to(bf16)).
    __nv_bfloat162 cpair = __floats2bfloat162_rn(c0 * scale, c1 * scale);
    __nv_bfloat162 spair = __floats2bfloat162_rn(s0 * scale, s1 * scale);

    // Map the pair back to output positions.  two_t is the low-half element
    // index; the high half is +64.  Both are even -> 4-byte aligned bf162.
    long two_t = t << 1;
    long row   = two_t >> 6;          // / 64
    long col   = two_t & (HALF - 1);  // % 64
    long lo    = (row << 7) + col;    // row*128 + col
    long hi    = lo + HALF;

    __nv_bfloat162* cptr = reinterpret_cast<__nv_bfloat162*>(cos_out);
    __nv_bfloat162* sptr = reinterpret_cast<__nv_bfloat162*>(sin_out);
    cptr[lo >> 1] = cpair;   // cos[..., col : col+2]
    cptr[hi >> 1] = cpair;   // cos[..., col+64 : col+66]  (duplicate)
    sptr[lo >> 1] = spair;
    sptr[hi >> 1] = spair;
}

