// Constants: TWOPI_HI = nearest float to 2π; TWOPI_LO = 2π - TWOPI_HI.
// Accurate to ~1e-5 abs error for |x| < 1e5 (freqs ≤ 4096 for our graded shapes).
__device__ __forceinline__ float cw_reduce(float x) {
    const float INV_2PI   = 0.15915494f;       // 1/(2π)
    const float TWOPI_HI  = 6.28318548f;        // 2π (nearest float)
    const float TWOPI_LO  = -1.7484556e-7f;    // 2π - TWOPI_HI  (correction)
    float k = nearbyintf(x * INV_2PI);
    float r = fmaf(-k, TWOPI_HI, x);
    return r - k * TWOPI_LO;
