    float r0 = cw_reduce(f0.x);
    float r1 = cw_reduce(f0.y);
    float r2 = cw_reduce(f0.z);
    float r3 = cw_reduce(f0.w);
    float r4 = cw_reduce(f1.x);
    float r5 = cw_reduce(f1.y);
    float r6 = cw_reduce(f1.z);
    float r7 = cw_reduce(f1.w);

