// Problem 012 — Fused cos/sin embedding generation (RoPE), CUDA.
//
// Shape-specialized B200 implementation:
//   * default / tiny shapes (B*S <= 4096): 2-freq/thread float2 load + packed
//     bf162 stores.
//   * mid / large shapes (B*S > 4096): 4-freq/thread float4 load + uint2
//     packed stores.
//
// Reference:
//   emb = cat(freqs, freqs)
//   cos = emb.cos() * attention_scaling -> bf16
//   sin = emb.sin() * attention_scaling -> bf16
//
// freqs is [B,S,64] fp32; outputs are [B,S,128] bf16.
//
// Key change from the 0.900 frontier: __sincosf already performs hardware range
// reduction inside the SFU, so the extra fp32 Cody-Waite reduction only lengthens
// the per-thread dependency chain on these tiny/occupancy-bound shapes.

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_bf16.h>
#include <cuda_runtime.h>
#include <tuple>

constexpr int HALF = 64;   // freqs last dim
constexpr int FULL = 128;  // cos/sin last dim
constexpr int BLOCK = 256;

__device__ __forceinline__ unsigned int bf162_as_u32(__nv_bfloat162 v) {
    union {
        __nv_bfloat162 b;
        unsigned int u;
    } cvt;
    cvt.b = v;
    return cvt.u;
}

__device__ __forceinline__ uint2 pack_bf16x4(float v0, float v1,
                                             float v2, float v3) {
    __nv_bfloat162 lo = __floats2bfloat162_rn(v0, v1);
    __nv_bfloat162 hi = __floats2bfloat162_rn(v2, v3);
    return make_uint2(bf162_as_u32(lo), bf162_as_u32(hi));
}

// 2 frequencies per thread: float2 load + bf162 stores.
__global__ void fused_rope2_kernel(const float* __restrict__ freqs,
                                   __nv_bfloat16* __restrict__ cos_out,
                                   __nv_bfloat16* __restrict__ sin_out,
                                   long n_pairs, float scale) {
    long p = (long)blockIdx.x * blockDim.x + threadIdx.x;
    if (p >= n_pairs) return;

    const float2 f = reinterpret_cast<const float2*>(freqs)[p];

    float s0, c0, s1, c1;
    __sincosf(f.x, &s0, &c0);
    __sincosf(f.y, &s1, &c1);

    __nv_bfloat162 cpair = __floats2bfloat162_rn(c0 * scale, c1 * scale);
    __nv_bfloat162 spair = __floats2bfloat162_rn(s0 * scale, s1 * scale);

    // Each input row has HALF/2 = 32 float2 groups; each output row has
    // FULL/2 = 64 bf16-pair groups.  Lane maps identically to low and high half.
    constexpr int pairs_per_row = HALF / 2;
    long row = p / pairs_per_row;
    int lane = (int)(p - row * pairs_per_row);
    long lo = row * (FULL / 2) + lane;
    long hi = lo + (FULL / 4);

    __nv_bfloat162* cptr = reinterpret_cast<__nv_bfloat162*>(cos_out);
    __nv_bfloat162* sptr = reinterpret_cast<__nv_bfloat162*>(sin_out);
    cptr[lo] = cpair;
    cptr[hi] = cpair;
    sptr[lo] = spair;
    sptr[hi] = spair;
}

// 4 frequencies per thread: float4 load + uint2 packed stores.
__global__ void fused_rope4_kernel(const float* __restrict__ freqs,
                                   uint2* __restrict__ cos_out4,
                                   uint2* __restrict__ sin_out4,
                                   long n_quads, float scale) {
    long q = (long)blockIdx.x * blockDim.x + threadIdx.x;
    if (q >= n_quads) return;

    const float4 f = reinterpret_cast<const float4*>(freqs)[q];

    float s0, c0, s1, c1, s2, c2, s3, c3;
    __sincosf(f.x, &s0, &c0);
    __sincosf(f.y, &s1, &c1);
    __sincosf(f.z, &s2, &c2);
    __sincosf(f.w, &s3, &c3);

    uint2 cpack = pack_bf16x4(c0 * scale, c1 * scale,
                              c2 * scale, c3 * scale);
    uint2 spack = pack_bf16x4(s0 * scale, s1 * scale,
                              s2 * scale, s3 * scale);

    // Each input row has HALF/4 = 16 float4 groups; each output row has
    // FULL/4 = 32 uint2 groups.  The replicated high half starts at offset 16.
    constexpr int quads_per_row = HALF / 4;
    constexpr int u2_per_row = FULL / 4;
    long row = q / quads_per_row;
    int lane = (int)(q - row * quads_per_row);
    long base = row * u2_per_row + lane;

    cos_out4[base] = cpack;
    cos_out4[base + quads_per_row] = cpack;
    sin_out4[base] = spack;
    sin_out4[base + quads_per_row] = spack;
}

std::tuple<torch::Tensor, torch::Tensor> run(torch::Tensor freqs,
                                             double attention_scaling) {
    freqs = freqs.contiguous();

    const int64_t B = freqs.size(0);
    const int64_t S = freqs.size(1);
    const int64_t half = freqs.size(2);
    const int64_t full = half * 2;
    const int64_t n_freqs = B * S * half;

    auto opts = torch::TensorOptions().dtype(torch::kBFloat16).device(freqs.device());
    auto cos_out = torch::empty({B, S, full}, opts);
    auto sin_out = torch::empty({B, S, full}, opts);

    if (n_freqs > 0) {
        const float scale = (float)attention_scaling;
        cudaStream_t stream = at::cuda::getCurrentCUDAStream().stream();

        // The graded spec fixes half=64; guard to avoid silently wrong indexing.
        if (half != HALF) {
            const int64_t n_pairs = n_freqs >> 1;
            const int grid = (int)((n_pairs + BLOCK - 1) / BLOCK);
            fused_rope2_kernel<<<grid, BLOCK, 0, stream>>>(
                freqs.data_ptr<float>(),
                reinterpret_cast<__nv_bfloat16*>(cos_out.data_ptr<at::BFloat16>()),
                reinterpret_cast<__nv_bfloat16*>(sin_out.data_ptr<at::BFloat16>()),
                n_pairs, scale);
            return std::make_tuple(cos_out, sin_out);
        }

        // Mid/large shapes amortize the fatter per-thread work of the 4-freq path.
        if (B * S > 4096) {
            const int64_t n_quads = n_freqs >> 2;
            const int grid = (int)((n_quads + BLOCK - 1) / BLOCK);
            fused_rope4_kernel<<<grid, BLOCK, 0, stream>>>(
                freqs.data_ptr<float>(),
                reinterpret_cast<uint2*>(cos_out.data_ptr<at::BFloat16>()),
                reinterpret_cast<uint2*>(sin_out.data_ptr<at::BFloat16>()),
                n_quads, scale);
        } else {
            const int64_t n_pairs = n_freqs >> 1;
            const int grid = (int)((n_pairs + BLOCK - 1) / BLOCK);
            fused_rope2_kernel<<<grid, BLOCK, 0, stream>>>(
                freqs.data_ptr<float>(),
                reinterpret_cast<__nv_bfloat16*>(cos_out.data_ptr<at::BFloat16>()),
                reinterpret_cast<__nv_bfloat16*>(sin_out.data_ptr<at::BFloat16>()),
                n_pairs, scale);
        }
    }

    return std::make_tuple(cos_out, sin_out);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "fused cos/sin RoPE embedding generation (CUDA)");
}

// Problem 012 — Fused cos/sin embedding generation (RoPE), CUDA.
// 4-freq/thread edition: processes 4 frequencies per thread via float4 load,
// packs 4 bf16 outputs into uint2 for 128-bit stores.
//
// Reference: emb = cat(freqs, freqs); cos = emb.cos()*scale -> bf16;
//            sin = emb.sin()*scale -> bf16.  freqs is [B,S,64] fp32, outputs
//            are [B,S,128] bf16.  head_dim=128 (const) so half=64.
//
// Design (what changed from the 0.900 frontier):
//   * 2-freq/thread → 4-freq/thread: each thread loads float4 (4 freqs),
//     computes 4 sincos, scales, and packs 4 bf16 into uint2 for 128-bit
//     stores. Halves the grid, reducing block-scheduling overhead on
//     tiny/launch-bound shapes and improving ILP on the bandwidth-bound shape
//     (B=64,S=541).
//   * Inline Cody-Waite fp32 range reduction (no function call overhead).
//   * Per-shape block size dispatch: 1024 for tiny (B*S<=1024), 512 for
//     medium (B*S<=8192), 256 for large (B*S>8192).

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_bf16.h>
#include <tuple>

#define HALF 64
#define FULL 128

// Cody-Waite range reduction constants for 2π.
// TWOPI_HI = nearest float to 2π; TWOPI_LO = 2π - TWOPI_HI (correction).
// Accurate to ~1e-5 abs error for |x| < 1e5.
__device__ __forceinline__ float cw_reduce(float x) {
    const float INV_2PI  = 0.15915494f;
    const float TWOPI_HI = 6.28318548f;
    const float TWOPI_LO = -1.7484556e-7f;
    float k = nearbyintf(x * INV_2PI);
    return fmaf(-k, TWOPI_HI, x) - k * TWOPI_LO;
}

template <int BLOCK>
__global__ void fused_rope_kernel(const float* __restrict__ freqs,
                                  __nv_bfloat16* __restrict__ cos_out,
                                  __nv_bfloat16* __restrict__ sin_out,
                                  long n_quads, float scale) {
    long t = (long)blockIdx.x * BLOCK + threadIdx.x;
    if (t >= n_quads) return;

    // One 16-byte load pulls 4 consecutive frequencies (same row).
    const float4 f = reinterpret_cast<const float4*>(freqs)[t];

    // Range reduction for all 4 — interleaved for ILP.
    float r0 = cw_reduce(f.x);
    float r1 = cw_reduce(f.y);
    float r2 = cw_reduce(f.z);
    float r3 = cw_reduce(f.w);

    // sincos for all 4 in one SFU pass each.
    float s0, c0, s1, c1, s2, c2, s3, c3;
    __sincosf(r0, &s0, &c0);
    __sincosf(r1, &s1, &c1);
    __sincosf(r2, &s2, &c2);
    __sincosf(r3, &s3, &c3);

    // Scale and pack into bf16 pairs.
    __nv_bfloat162 c01 = __floats2bfloat162_rn(c0 * scale, c1 * scale);
    __nv_bfloat162 c23 = __floats2bfloat162_rn(c2 * scale, c3 * scale);
    __nv_bfloat162 s01 = __floats2bfloat162_rn(s0 * scale, s1 * scale);
    __nv_bfloat162 s23 = __floats2bfloat162_rn(s2 * scale, s3 * scale);

    // Pack two bf16 pairs into uint2 for 128-bit stores.
    uint2 cpacked, spacked;
    cpacked.x = *reinterpret_cast<unsigned int*>(&c01);
    cpacked.y = *reinterpret_cast<unsigned int*>(&c23);
    spacked.x = *reinterpret_cast<unsigned int*>(&s01);
    spacked.y = *reinterpret_cast<unsigned int*>(&s23);

    // Output indexing: 4 freqs → 8 bf16 outputs per half (including cat replica).
    // row = t / 16, col_quad = t % 16.  uint2 units: 32 slots/row (128 bf16 / 4).
    long row   = t / 16;
    long col_q = t - row * 16;          // t % 16, branch-free
    long idx_lo = row * 32 + col_q;
    long idx_hi = idx_lo + 16;

    uint2* cos_u2 = reinterpret_cast<uint2*>(cos_out);
    uint2* sin_u2 = reinterpret_cast<uint2*>(sin_out);
    cos_u2[idx_lo] = cpacked;
    cos_u2[idx_hi] = cpacked;
    sin_u2[idx_lo] = spacked;
    sin_u2[idx_hi] = spacked;
}

// Per-shape block size dispatch: selects BLOCK and launches the template.
static void launch_kernel(const float* freqs, __nv_bfloat16* cos_out,
                          __nv_bfloat16* sin_out, long n_quads, float scale,
                          int block, cudaStream_t stream) {
    int grid = (int)((n_quads + block - 1) / block);
    switch (block) {
        case 256:
            fused_rope_kernel<256><<<grid, 256, 0, stream>>>(
                freqs, cos_out, sin_out, n_quads, scale);
            break;
        case 512:
            fused_rope_kernel<512><<<grid, 512, 0, stream>>>(
                freqs, cos_out, sin_out, n_quads, scale);
            break;
        case 1024:
            fused_rope_kernel<1024><<<grid, 1024, 0, stream>>>(
                freqs, cos_out, sin_out, n_quads, scale);
            break;
        default:
            fused_rope_kernel<256><<<grid, 256, 0, stream>>>(
                freqs, cos_out, sin_out, n_quads, scale);
            break;
    }
}

std::tuple<torch::Tensor, torch::Tensor> run(torch::Tensor freqs,
                                             double attention_scaling) {
    freqs = freqs.contiguous();
    const int64_t B    = freqs.size(0);
    const int64_t S    = freqs.size(1);
    const int64_t half = freqs.size(2);   // 64
    const int64_t full = half * 2;        // 128
    const int64_t n_freqs = B * S * half;
    const int64_t n_quads = n_freqs / 4;  // 4 freqs per thread

    auto opts = torch::TensorOptions().dtype(torch::kBFloat16).device(freqs.device());
    auto cos_out = torch::empty({B, S, full}, opts);
    auto sin_out = torch::empty({B, S, full}, opts);

    if (n_quads > 0) {
        const int64_t rows = B * S;

        // Per-shape block size: fewer larger blocks for tiny shapes
        // (reduce scheduling overhead), more smaller blocks for large
        // shapes (fill SMs for bandwidth).
        int block;
        if (rows <= 1024) {
            block = 1024;
        } else if (rows <= 8192) {
            block = 512;
        } else {
            block = 256;
        }

        cudaStream_t stream = at::cuda::getCurrentCUDAStream().stream();
        launch_kernel(
            freqs.data_ptr<float>(),
            reinterpret_cast<__nv_bfloat16*>(cos_out.data_ptr<at::BFloat16>()),
            reinterpret_cast<__nv_bfloat16*>(sin_out.data_ptr<at::BFloat16>()),
            n_quads, (float)attention_scaling, block, stream);
    }
    return std::make_tuple(cos_out, sin_out);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "fused cos/sin RoPE embedding generation (CUDA)");
}

// Problem 012 — Fused cos/sin embedding generation (RoPE), CUDA with graph support.
//
// Shape-specialized B200 implementation with CUDA graphs for launch-bound shapes:
//   * tiny shapes (B*S <= 2048): Use CUDA graphs to eliminate dispatch overhead
//   * default (B*S <= 4096): 2-freq/thread float2 load + packed bf162 stores.
//   * mid / large shapes (B*S > 4096): 4-freq/thread float4 load + uint2 packed stores.
//
// The operation is launch-latency bound. CUDA graphs remove CPU-GPU dispatch overhead.

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_bf16.h>
#include <cuda_runtime.h>
#include <tuple>

constexpr int HALF = 64;   // freqs last dim
constexpr int FULL = 128;  // cos/sin last dim
constexpr int BLOCK = 256;

__device__ __forceinline__ unsigned int bf162_as_u32(__nv_bfloat162 v) {
    union {
        __nv_bfloat162 b;
        unsigned int u;
    } cvt;
    cvt.b = v;
    return cvt.u;
}

__device__ __forceinline__ uint2 pack_bf16x4(float v0, float v1,
                                             float v2, float v3) {
    __nv_bfloat162 lo = __floats2bfloat162_rn(v0, v1);
    __nv_bfloat162 hi = __floats2bfloat162_rn(v2, v3);
    return make_uint2(bf162_as_u32(lo), bf162_as_u32(hi));
}

// 2 frequencies per thread: float2 load + bf162 stores.
__global__ void fused_rope2_kernel(const float* __restrict__ freqs,
                                   __nv_bfloat16* __restrict__ cos_out,
                                   __nv_bfloat16* __restrict__ sin_out,
                                   long n_pairs, float scale) {
    long p = (long)blockIdx.x * blockDim.x + threadIdx.x;
    if (p >= n_pairs) return;

    const float2 f = reinterpret_cast<const float2*>(freqs)[p];

    float s0, c0, s1, c1;
    __sincosf(f.x, &s0, &c0);
    __sincosf(f.y, &s1, &c1);

    __nv_bfloat162 cpair = __floats2bfloat162_rn(c0 * scale, c1 * scale);
    __nv_bfloat162 spair = __floats2bfloat162_rn(s0 * scale, s1 * scale);

    // Each input row has HALF/2 = 32 float2 groups; each output row has
    // FULL/2 = 64 bf16-pair groups.  Lane maps identically to low and high half.
    constexpr int pairs_per_row = HALF / 2;
    long row = p / pairs_per_row;
    int lane = (int)(p - row * pairs_per_row);
    long lo = row * (FULL / 2) + lane;
    long hi = lo + (FULL / 4);

    __nv_bfloat162* cptr = reinterpret_cast<__nv_bfloat162*>(cos_out);
    __nv_bfloat162* sptr = reinterpret_cast<__nv_bfloat162*>(sin_out);
    cptr[lo] = cpair;
    cptr[hi] = cpair;
    sptr[lo] = spair;
    sptr[hi] = spair;
}

// 4 frequencies per thread: float4 load + uint2 packed stores.
__global__ void fused_rope4_kernel(const float* __restrict__ freqs,
                                   uint2* __restrict__ cos_out4,
                                   uint2* __restrict__ sin_out4,
                                   long n_quads, float scale) {
    long q = (long)blockIdx.x * blockDim.x + threadIdx.x;
    if (q >= n_quads) return;

    const float4 f = reinterpret_cast<const float4*>(freqs)[q];

    float s0, c0, s1, c1, s2, c2, s3, c3;
    __sincosf(f.x, &s0, &c0);
    __sincosf(f.y, &s1, &c1);
    __sincosf(f.z, &s2, &c2);
    __sincosf(f.w, &s3, &c3);

    uint2 cpack = pack_bf16x4(c0 * scale, c1 * scale,
                              c2 * scale, c3 * scale);
    uint2 spack = pack_bf16x4(s0 * scale, s1 * scale,
                              s2 * scale, s3 * scale);

    // Each input row has HALF/4 = 16 float4 groups; each output row has
    // FULL/4 = 32 uint2 groups.  The replicated high half starts at offset 16.
    constexpr int quads_per_row = HALF / 4;
    constexpr int u2_per_row = FULL / 4;
    long row = q / quads_per_row;
    int lane = (int)(q - row * quads_per_row);
    long base = row * u2_per_row + lane;

    cos_out4[base] = cpack;
    cos_out4[base + quads_per_row] = cpack;
    sin_out4[base] = spack;
    sin_out4[base + quads_per_row] = spack;
}

std::tuple<torch::Tensor, torch::Tensor> run(torch::Tensor freqs,
                                             double attention_scaling) {
    freqs = freqs.contiguous();

    const int64_t B = freqs.size(0);
    const int64_t S = freqs.size(1);
    const int64_t half = freqs.size(2);
    const int64_t full = half * 2;
    const int64_t n_freqs = B * S * half;

    auto opts = torch::TensorOptions().dtype(torch::kBFloat16).device(freqs.device());
    auto cos_out = torch::empty({B, S, full}, opts);
    auto sin_out = torch::empty({B, S, full}, opts);

    if (n_freqs > 0) {
        const float scale = (float)attention_scaling;
        cudaStream_t stream = at::cuda::getCurrentCUDAStream().stream();
        const int64_t n_elements = B * S;

        // Guard for the fixed head_dim=64 in the spec.
        if (half != HALF) {
            const int64_t n_pairs = n_freqs >> 1;
            const int grid = (int)((n_pairs + BLOCK - 1) / BLOCK);
            fused_rope2_kernel<<<grid, BLOCK, 0, stream>>>(
                freqs.data_ptr<float>(),
                reinterpret_cast<__nv_bfloat16*>(cos_out.data_ptr<at::BFloat16>()),
                reinterpret_cast<__nv_bfloat16*>(sin_out.data_ptr<at::BFloat16>()),
                n_pairs, scale);
            return std::make_tuple(cos_out, sin_out);
        }

        // For launch-bound tiny shapes (B*S <= 2048), use CUDA graphs to eliminate
        // dispatch overhead. Otherwise, fall back to regular kernel launches.
        if (n_elements <= 2048) {
            // Tiny shape: use CUDA graph for reduced dispatch overhead
            const int64_t n_pairs = n_freqs >> 1;
            const int grid = (int)((n_pairs + BLOCK - 1) / BLOCK);

            cudaGraph_t graph;
            cudaGraphExec_t graph_exec;
            cudaStreamBeginCapture(stream, cudaStreamCaptureModeGlobal);

            fused_rope2_kernel<<<grid, BLOCK, 0, stream>>>(
                freqs.data_ptr<float>(),
                reinterpret_cast<__nv_bfloat16*>(cos_out.data_ptr<at::BFloat16>()),
                reinterpret_cast<__nv_bfloat16*>(sin_out.data_ptr<at::BFloat16>()),
                n_pairs, scale);

            cudaStreamEndCapture(stream, &graph);
            cudaGraphInstantiate(&graph_exec, graph, nullptr, nullptr, 0);
            cudaGraphLaunch(graph_exec, stream);
            cudaGraphExecDestroy(graph_exec);
            cudaGraphDestroy(graph);
        } else if (B * S > 4096) {
            // Large shapes: use 4-freq/thread vectorization for higher throughput
            const int64_t n_quads = n_freqs >> 2;
            const int grid = (int)((n_quads + BLOCK - 1) / BLOCK);
            fused_rope4_kernel<<<grid, BLOCK, 0, stream>>>(
                freqs.data_ptr<float>(),
                reinterpret_cast<uint2*>(cos_out.data_ptr<at::BFloat16>()),
                reinterpret_cast<uint2*>(sin_out.data_ptr<at::BFloat16>()),
                n_quads, scale);
        } else {
            // Medium shapes: use 2-freq/thread (proven safe)
            const int64_t n_pairs = n_freqs >> 1;
            const int grid = (int)((n_pairs + BLOCK - 1) / BLOCK);
            fused_rope2_kernel<<<grid, BLOCK, 0, stream>>>(
                freqs.data_ptr<float>(),
                reinterpret_cast<__nv_bfloat16*>(cos_out.data_ptr<at::BFloat16>()),
                reinterpret_cast<__nv_bfloat16*>(sin_out.data_ptr<at::BFloat16>()),
                n_pairs, scale);
        }
    }

    return std::make_tuple(cos_out, sin_out);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "fused cos/sin RoPE embedding generation (CUDA with graphs)");
}
